import { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";
import api from "../utils/api";

const STATUS_LABEL = {
  pending: "Хүлээгдэж буй",
  confirmed: "Баталгаажсан",
  cancelled: "Цуцлагдсан",
  completed: "Дууссан",
};
const STATUS_CLASS = {
  pending: "badge-pending",
  confirmed: "badge-confirmed",
  cancelled: "badge-cancelled",
  completed: "badge-completed",
};

export default function MyBookingsPage() {
  const { user } = useAuth();
  const nav = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [tab, setTab] = useState("all");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) {
      nav("/login");
      return;
    }
    load();
  }, []); // eslint-disable-line

  const load = async () => {
    setLoading(true);
    const { data } = await api.get("/bookings/my");
    setBookings(data.data);
    setLoading(false);
  };

  const cancel = async (id) => {
    if (!window.confirm("Захиалгыг цуцлах уу?")) return;
    await api.put(`/bookings/${id}/cancel`);
    load();
  };

  const filtered =
    tab === "all"
      ? bookings
      : tab === "active"
        ? bookings.filter((b) => ["pending", "confirmed"].includes(b.status))
        : bookings.filter((b) => ["cancelled", "completed"].includes(b.status));

  const fmt = (dt) =>
    new Date(dt).toLocaleString("mn-MN", {
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
    });

  const CAT_ICONS = {
    salon: "💇",
    barber: "✂",
    beauty: "💄",
    billiard: "🎱",
    restaurant: "🍽",
    resort: "🏞",
    other: "📍",
  };

  return (
    <div style={{ maxWidth: 760, margin: "0 auto", padding: "32px 20px" }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 28, fontWeight: 800, marginBottom: 6 }}>
          Миний захиалгууд
        </h1>
        <p style={{ color: "var(--muted)", fontSize: 14 }}>
          Таны захиалсан үйлчилгээнүүдийн жагсаалт болон төлөв.
        </p>
      </div>

      {/* Tabs */}
      <div
        style={{
          display: "flex",
          gap: 4,
          marginBottom: 20,
          borderBottom: "1px solid var(--border)",
          paddingBottom: 0,
        }}
      >
        {[
          ["all", "Бүгд"],
          ["active", "Идэвхтэй"],
          ["past", "Өнгөрсөн"],
        ].map(([k, l]) => (
          <button
            key={k}
            onClick={() => setTab(k)}
            style={{
              padding: "10px 20px",
              background: "none",
              border: "none",
              cursor: "pointer",
              fontSize: 14,
              fontWeight: 500,
              color: tab === k ? "var(--text)" : "var(--muted)",
              borderBottom:
                tab === k ? "2px solid var(--blue)" : "2px solid transparent",
              marginBottom: -1,
            }}
          >
            {l} {k === "all" ? `(${bookings.length})` : ""}
          </button>
        ))}
      </div>

      {/* List */}
      {loading ? (
        <div
          style={{ textAlign: "center", padding: 40, color: "var(--muted)" }}
        >
          Ачаалж байна...
        </div>
      ) : filtered.length === 0 ? (
        <div
          style={{ textAlign: "center", padding: 60, color: "var(--muted)" }}
        >
          <div style={{ fontSize: 40, marginBottom: 12 }}>📋</div>
          <div>Захиалга байхгүй байна</div>
          <Link
            to="/"
            className="btn btn-primary"
            style={{ marginTop: 16, display: "inline-flex" }}
          >
            Захиалга хийх
          </Link>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {filtered.map((b) => (
            <div
              key={b._id}
              className="card"
              style={{
                display: "flex",
                gap: 16,
                alignItems: "flex-start",
                padding: 16,
              }}
            >
              {/* Image */}
              <div
                style={{
                  width: 100,
                  height: 80,
                  borderRadius: 8,
                  overflow: "hidden",
                  background: "var(--surface)",
                  flexShrink: 0,
                }}
              >
                {b.placeId?.images?.[0] ? (
                  <img
                    src={b.placeId.images[0]}
                    alt=""
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                    }}
                  />
                ) : (
                  <div
                    style={{
                      height: "100%",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontSize: 28,
                    }}
                  >
                    {CAT_ICONS[b.placeId?.category] || "📍"}
                  </div>
                )}
              </div>

              {/* Info */}
              <div style={{ flex: 1 }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: 6,
                  }}
                >
                  <span className={`badge ${STATUS_CLASS[b.status]}`}>
                    ● {STATUS_LABEL[b.status]}
                  </span>
                  <span style={{ fontSize: 12, color: "var(--muted)" }}>
                    #{b._id.slice(-4).toUpperCase()}
                  </span>
                </div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  {b.placeId?.name}
                </div>
                <div
                  style={{
                    display: "flex",
                    gap: 16,
                    fontSize: 13,
                    color: "var(--muted)",
                  }}
                >
                  <span>✂ {b.serviceId?.name}</span>
                  <span>🕐 {fmt(b.datetime)}</span>
                  {b.staffId && <span>👤 {b.staffId.name}</span>}
                  {b.tableId && <span>🍽 Ширээ</span>}
                </div>
                {b.totalPrice > 0 && (
                  <div
                    style={{
                      marginTop: 6,
                      fontSize: 14,
                      fontWeight: 600,
                      color: "var(--blue)",
                    }}
                  >
                    ₮{b.totalPrice.toLocaleString()}
                  </div>
                )}
              </div>

              {/* Actions */}
              <div
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: 8,
                  flexShrink: 0,
                }}
              >
                <Link
                  to={`/place/${b.placeId?._id}`}
                  className="btn btn-outline btn-sm"
                >
                  Дэлгэрэнгүй
                </Link>
                {["pending", "confirmed"].includes(b.status) && (
                  <button
                    onClick={() => cancel(b._id)}
                    className="btn btn-danger btn-sm"
                  >
                    Цуцлах
                  </button>
                )}
                {b.status === "cancelled" && (
                  <Link
                    to={`/book/${b.placeId?._id}`}
                    className="btn btn-primary btn-sm"
                  >
                    Дахин захиалах
                  </Link>
                )}
